package jetbrains.mps.tool.make;

/*Generated by MPS */

import jetbrains.mps.tool.environment.ProjectStrategy;
import java.util.Collection;
import java.io.File;
import org.jetbrains.annotations.NotNull;
import jetbrains.mps.project.Project;
import jetbrains.mps.tool.environment.Environment;
import jetbrains.mps.vfs.IFileSystem;
import jetbrains.mps.vfs.VFSManager;
import jetbrains.mps.library.ModulesMiner;
import jetbrains.mps.internal.collections.runtime.CollectionSequence;
import jetbrains.mps.tool.environment.ProjectModulesFiller;

/*package*/ final class ModuleSetForProject implements ProjectStrategy {
  private final Collection<File> myModuleFiles;

  /*package*/ ModuleSetForProject(@NotNull Collection<File> moduleFiles) {
    myModuleFiles = moduleFiles;
  }

  @NotNull
  @Override
  public Project create(@NotNull Environment env) {
    // pretty much what FromModulesListProjectStrategy does; independent of IDEA App, not in [testbench] and
    // tailored for the Make ant integration (although worth refactoring to be generic code)
    //  
    IFileSystem localFS = env.getPlatform().findComponent(VFSManager.class).getFileSystem(VFSManager.JAVA_IO_FILE_FS);
    // XXX I feel ant would be better with IO IFile, need to use another one if I'm wrong
    ModulesMiner mm = new ModulesMiner(env.getPlatform());
    for (File f : CollectionSequence.fromCollection(myModuleFiles)) {
      mm.collectModules(localFS.getFile(f));
    }
    Project p = env.createEmptyProject();
    ProjectModulesFiller pmf = new ProjectModulesFiller(p, mm.getCollectedModules());
    return pmf.load();
  }


  @Override
  public boolean isApplicable() {
    return true;
  }
}
